import java.io.*;
public class ExternDemo {
    static class Config implements Externalizable {
        int timeout; String host;
        public Config() {}  // required for Externalizable
        Config(int t, String h) { timeout=t; host=h; }
        public void writeExternal(ObjectOutput out) throws IOException {
            out.writeInt(timeout);
            out.writeUTF(host);
        }
        public void readExternal(ObjectInput in) throws Exception {
            timeout = in.readInt();
            host = in.readUTF();
        }
    }
    public static void main(String[] args) throws Exception {
        Config c = new Config(30, "localhost");
        ByteArrayOutputStream bos = new ByteArrayOutputStream();
        new ObjectOutputStream(bos).writeObject(c);
        Config c2 = (Config) new ObjectInputStream(
            new ByteArrayInputStream(bos.toByteArray())).readObject();
        System.out.println(c2.timeout);
        System.out.println(c2.host);
    }
}
